CREATE DEFINER=`root`@`localhost` PROCEDURE `InsertAttendanceData` ()   BEGIN
    DECLARE currentDate DATE;
    DECLARE endDate DATE;
    DECLARE employeeId INT;
    DECLARE jobTitle VARCHAR(50); -- Pindahkan deklarasi ke awal blok

    SET currentDate = '2025-03-01';
    SET endDate = '2025-03-30';

    -- Loop through all dates in the range
    WHILE currentDate <= endDate DO
        -- Loop through employee IDs
        SET employeeId = 4;
        WHILE employeeId <= 40 DO
            -- Get the job title for the current employee
            SELECT jabatan INTO jobTitle
            FROM karyawans
            WHERE id = employeeId;

            -- Insert based on job title and day
            IF (jobTitle IN ('Driver', 'Technical Support') AND DAYOFWEEK(currentDate) IN (2, 3, 4, 5, 6, 7)) -- Monday to Saturday
               OR (jobTitle = 'Office Boy') -- Every day
               OR (jobTitle NOT IN ('Driver', 'Technical Support', 'Office Boy') AND DAYOFWEEK(currentDate) IN (2, 3, 4, 5, 6)) THEN -- Monday to Friday for others
                    id_karyawan, 
                    tanggal, 
                    jam_masuk, 
                    jam_keluar, 
                    keterangan,
                    keterangan_pulang,
                    waktu_keterlambatan, 
                    foto, 
                    created_at, 
                    updated_at
                ) VALUES (
                    employeeId,
                    currentDate,
                    '08:00:00',
                    null,
                    'Masuk (Kantor)',
                    'Pulang (Kantor)',
                    '00:00:00',
                    NULL,
                    NOW(),
                    NOW()
                );
            END IF;

            SET employeeId = employeeId + 1;
        END WHILE;

        SET currentDate = DATE_ADD(currentDate, INTERVAL 1 DAY);
    END WHILE;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `InsertData` ()   BEGIN
    DECLARE v_sales_key VARCHAR(255);
    DECLARE v_materi_key INT;
    DECLARE v_perusahaan_key INT;
    DECLARE v_harga_jual INT DEFAULT 10000000;
    DECLARE v_pax INT;
    DECLARE v_isi_pax INT;
    DECLARE v_tanggal_awal DATE;
    DECLARE v_tanggal_akhir DATE;
    DECLARE v_metode_kelas VARCHAR(255) DEFAULT 'offline';
    DECLARE v_event VARCHAR(255) DEFAULT 'kelas';
    DECLARE v_ruang INT;
    DECLARE v_instruktur_key VARCHAR(255);
    DECLARE v_status ENUM('0', '1') DEFAULT '0';
    DECLARE v_exam ENUM('0', '1') DEFAULT '0';
    DECLARE v_authorize ENUM('0', '1') DEFAULT '0';
    DECLARE v_bulan INT DEFAULT 3;  -- March
    DECLARE v_quartal INT DEFAULT 1;  -- Q1
    DECLARE v_random_day INT;

    -- Generate random sales_key
    SET v_sales_key = (SELECT ELT(FLOOR(1 + RAND() * 4), 'HW', 'RR', 'AN', 'NA'));

    -- Generate random materi_key and perusahaan_key
    SET v_materi_key = FLOOR(1 + RAND() * 276);
    SET v_perusahaan_key = FLOOR(1 + RAND() * 300);

    -- Generate random pax and isi_pax
    SET v_pax = FLOOR(1 + RAND() * 7);
    SET v_isi_pax = v_pax;

    -- Loop to generate a valid tanggal_awal
    WHILE v_tanggal_awal IS NULL DO
        SET v_tanggal_awal = (SELECT DATE_ADD('2025-03-01', INTERVAL FLOOR(RAND() * 22) DAY)
                               WHERE DAYOFWEEK(DATE_ADD('2025-03-01', INTERVAL FLOOR(RAND() * 22) DAY)) NOT IN (1, 7)
                               LIMIT 1);
    END WHILE;

    -- Generate tanggal_akhir within the same week
    SET v_random_day = FLOOR(RAND() * 4);  -- 0 to 3 days later
    SET v_tanggal_akhir = DATE_ADD(v_tanggal_awal, INTERVAL v_random_day DAY);

    -- Generate random ruang
    SET v_ruang = FLOOR(1 + RAND() * 5);

    -- Generate random instruktur_key
    SET v_instruktur_key = (SELECT ELT(FLOOR(1 + RAND() * 6), 'AD', 'SB', 'WY', 'YN', 'PN', 'LU'));

    -- Insert the data into the table
        sales_key,
        materi_key,
        perusahaan_key,
        harga_jual,
        pax,
        isi_pax,
        tanggal_awal,
        tanggal_akhir,
        metode_kelas,
        event,
        ruang,
        instruktur_key,
        status,
        exam,
        authorize,
        bulan,
        quartal,
        tahun
    ) VALUES (
        v_sales_key,
        v_materi_key,
        v_perusahaan_key,
        v_harga_jual,
        v_pax,
        v_isi_pax,
        v_tanggal_awal,
        v_tanggal_akhir,
        v_metode_kelas,
        v_event,
        v_ruang,
        v_instruktur_key,
        v_status,
        v_exam,
        v_authorize,
        v_bulan,
        v_quartal,
        2025  -- tahun
    );
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `UpdateJamKeluar` ()   BEGIN
    UPDATE absensi_karyawans 
    SET jam_keluar = CONCAT('17:', 
                            LPAD(FLOOR(RAND() * 60), 2, '0'), 
                            ':', 
                            LPAD(FLOOR(RAND() * 60), 2, '0')) 
    WHERE jam_keluar IS NULL 
      AND (jam_masuk >= '03:00:00' AND jam_masuk <= '12:00:00')
      AND id_karyawan IN (SELECT id FROM karyawans WHERE jabatan NOT IN ('Office Boy', 'Driver'));
END$$

DELIMITER ;

